THE CLAIM:
{
 "title": "Selling to slow large operators cuts Year-1 capture tenfold",
 "narrative": "The model says the venture wins 3% of its serviceable market in Year 1, spread evenly across buyers. But the venture has chosen to focus Year 1 on large operators, the slowest buyers, whose qualification cycle runs longer than the 12-month horizon. Comparable hardware entrants started near 0.001% of the market in their first year. That points to a Year-1 revenue number roughly ten times too high.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "Year-1 plan targets large operators held by incumbents with qualification gates",
   "refs": [
    "profile:Who is the primary buyer you'll sell through first?",
    "profile:Stage",
    "digest:cust-mix#c9"
   ]
  },
  {
   "step": "propagation",
   "text": "The 3% rests on generic SOM benchmarks ignoring these buyers' cycle length",
   "refs": [
    "ledger:obtainableFactor",
    "ledger:cust.operator-large"
   ]
  },
  {
   "step": "model-impact",
   "text": "Focused on the slowest buyers, Year-1 revenue is overstated tenfold",
   "refs": [
    "ledger:obtainableFactor",
    "digest:cust-mix#c0"
   ]
  }
 ],
 "falsifier": "A documented case of a new rack-PDU or comparable hardware entrant closing 3% of a regional market within 12 months selling direct to large operators, or the venture's first order completing in under 6 months.",
 "category": "execution",
 "evidence": [
  {
   "title": "NVIDIA Supply Chain Certification",
   "sourceType": "industry-report",
   "publisher": "Grokipedia",
   "date": null,
   "excerpt": "Central to this certification framework are the Recommended Vendor List (RVL) and Approved Vendor List (AVL), which serve as key tools for validating and qualifying vendors for specific hardware components, such as cooling distribution units (CDUs)",
   "url": "https://grokipedia.com/page/NVIDIA_Supply_Chain_Certification",
   "attached": true
  },
  {
   "title": "Addressable Markets: TAM, SAM & SOM Guide (2026)",
   "sourceType": "industry-report",
   "publisher": "Prospeo",
   "date": null,
   "excerpt": "SOM benchmarks that won't get you laughed out of the room: 1% of SAM in Year 1, 3% in Year 2, 5% in Year 3.",
   "url": "https://prospeo.io/s/addressable-markets",
   "attached": true
  },
  {
   "title": "How to Calculate SOM Step-by-Step Guide",
   "sourceType": "industry-report",
   "publisher": "Profitjets",
   "date": "2026-04-03",
   "excerpt": "the number changes when your hiring plan, pipeline creation, win rate, deal size, or sales cycle changes",
   "url": "https://profitjets.com/blog/how-to-calculate-som/",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "obtainableFactor",
  "label": "Year-1 obtainable share of SAM",
  "kind": "assumption",
  "value": 0.03,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "triangulated",
  "dimension": null,
  "dimensionValue": null,
  "sensitivityRange": {
   "low": 0.01,
   "high": 0.05
  },
  "funnelActive": true,
  "derivation": {
   "method": "Benchmark anchoring",
   "expression": "Year-1 SOM benchmarks: 1% of SAM (Prospeo); early-stage range 1–5% (IdeaPlan) → curated 3% mid-band",
   "crossCheck": "Prior 6% assumption sat above every year-1 benchmark found — revised down"
  },
  "provenance": {
   "rationale": "Two independent benchmark sources agree on 1–5%, but both are generic (not DC-hardware-specific) → inferred.",
   "promotionPath": "Replace with pipeline-based model once first CE deals close (win-rate × cycle time × capacity)."
  },
  "evidence": [
   {
    "title": "Addressable markets — SOM benchmarks",
    "sourceType": "analyst-estimate",
    "publisher": "Prospeo",
    "date": null,
    "excerpt": "SOM benchmarks that won't get you laughed out of the room: 1% of SAM in Year 1, 3% in Year 2, 5% in Year 3.",
    "attached": true
   },
   {
    "title": "Serviceable Obtainable Market (SOM) — early-stage ranges",
    "sourceType": "analyst-estimate",
    "publisher": "IdeaPlan",
    "date": "2024",
    "excerpt": "For early-stage companies, SOM is typically 1-5% of SAM. For growing companies with product-market fit, SOM can reach 10-20% of SAM.",
    "attached": true
   }
  ]
 }
]

Emit JSON: { resolution: "error"|"risk", settleTest, proposedCorrection: {nodeId, value, low, high, rationale} or null, researchQueries: [{query, kind}] ([] for risks) }
